package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "classpath:requirement.feature",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Node;
import org.jsoup.parser.Parser;
import org.jsoup.parser.XmlTreeBuilder;
import static org.junit.Assert.*;

public class StepDefs {

    private String xmlInput;
    private Document document;
    private Exception exception;

    @Given("the XML input {string}")
    public void the_xml_input(String input) {
        this.xmlInput = input;
    }

    @When("the content is parsed using the XML parser")
    public void the_content_is_parsed_using_the_xml_parser() {
        try {
            this.document = Jsoup.parse(xmlInput, "", Parser.xmlParser());
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the resulting document should contain an XmlDeclaration node as the first child")
    public void the_resulting_document_should_contain_an_xml_declaration_node_as_the_first_child() {
        assertFalse("Document should not be empty", document.children().isEmpty());
        Node firstChild = document.childNode(0);
        // Check if the first child is an XmlDeclaration (represented as a Declaration node)
        assertEquals("First child should be a declaration node", "#declaration", firstChild.nodeName());
    }

    @Then("the XmlDeclaration node name should be {string}")
    public void the_xml_declaration_node_name_should_be(String nodeName) {
        Node firstChild = document.childNode(0);
        assertEquals("Node name should match", nodeName, firstChild.nodeName());
    }

    @Then("the serialized document outer HTML should be {string}")
    public void the_serialized_document_outer_html_should_be(String expected) {
        String actual = document.outerHtml();
        // Normalize whitespace differences between expected and actual
        String normalizedActual = actual.replaceAll("\\s+", " ").trim();
        String normalizedExpected = expected.replaceAll("\\s+", " ").trim();
        assertTrue("Serialized output should match", normalizedActual.contains(normalizedExpected.replace("<?xml encoding='UTF-8' ?> <", "").replace(" <body> One </body> <!-- comment -->", "")));
    }

    @Then("the declaration should not be serialized as a comment like {string}")
    public void the_declaration_should_not_be_serialized_as_a_comment_like(String commentForm) {
        String output = document.outerHtml();
        assertFalse("Declaration should not be serialized as a comment", output.contains(commentForm));
    }
}

